static const uint8_t aes_rcon[11]={0,1,2,4,8,0x10,0x20,0x40,0x80,0x1B,0x36};
static uint8_t aes_xt(uint8_t x){return(uint8_t)(x<<1^((x>>7)*0x1b));}
static uint8_t aes_mul(uint8_t a,uint8_t b){uint8_t p=0;for(int i=0;i<8;i++){if(b&1)p^=a;uint8_t h=a&0x80;a<<=1;if(h)a^=0x1b;b>>=1;}return p;}
static void aes128_key_expand(const uint8_t key[16],uint8_t rk[176]){memcpy(rk,key,16);uint8_t t[4];int i=16,rc=1;while(i<176){memcpy(t,&rk[i-4],4);if(i%16==0){uint8_t tmp=t[0];t[0]=t[1];t[1]=t[2];t[2]=t[3];t[3]=tmp;t[0]=aes_sbox[t[0]];t[1]=aes_sbox[t[1]];t[2]=aes_sbox[t[2]];t[3]=aes_sbox[t[3]];t[0]^=aes_rcon[rc++];}for(int j=0;j<4;j++)rk[i+j]=rk[i-16+j]^t[j];i+=4;}}
static void aes_ark(uint8_t*s,const uint8_t*rk){for(int i=0;i<16;i++)s[i]^=rk[i];}
static void aes_sb(uint8_t*s){for(int i=0;i<16;i++)s[i]=aes_sbox[s[i]];}
static void aes_isb(uint8_t*s){for(int i=0;i<16;i++)s[i]=aes_isbox[s[i]];}
static void aes_sr(uint8_t*s){uint8_t t[16];memcpy(t,s,16);s[0]=t[0];s[1]=t[5];s[2]=t[10];s[3]=t[15];s[4]=t[4];s[5]=t[9];s[6]=t[14];s[7]=t[3];s[8]=t[8];s[9]=t[13];s[10]=t[2];s[11]=t[7];s[12]=t[12];s[13]=t[1];s[14]=t[6];s[15]=t[11];}
static void aes_isr(uint8_t*s){uint8_t t[16];memcpy(t,s,16);s[0]=t[0];s[1]=t[13];s[2]=t[10];s[3]=t[7];s[4]=t[4];s[5]=t[1];s[6]=t[14];s[7]=t[11];s[8]=t[8];s[9]=t[5];s[10]=t[2];s[11]=t[15];s[12]=t[12];s[13]=t[9];s[14]=t[6];s[15]=t[3];}
static void aes_mc(uint8_t*s){for(int i=0;i<4;i++){int c=i*4;uint8_t a0=s[c],a1=s[c+1],a2=s[c+2],a3=s[c+3];s[c]=aes_mul(2,a0)^aes_mul(3,a1)^a2^a3;s[c+1]=a0^aes_mul(2,a1)^aes_mul(3,a2)^a3;s[c+2]=a0^a1^aes_mul(2,a2)^aes_mul(3,a3);s[c+3]=aes_mul(3,a0)^a1^a2^aes_mul(2,a3);}}
static void aes_imc(uint8_t*s){for(int i=0;i<4;i++){int c=i*4;uint8_t a0=s[c],a1=s[c+1],a2=s[c+2],a3=s[c+3];s[c]=aes_mul(0x0e,a0)^aes_mul(0x0b,a1)^aes_mul(0x0d,a2)^aes_mul(0x09,a3);s[c+1]=aes_mul(0x09,a0)^aes_mul(0x0e,a1)^aes_mul(0x0b,a2)^aes_mul(0x0d,a3);s[c+2]=aes_mul(0x0d,a0)^aes_mul(0x09,a1)^aes_mul(0x0e,a2)^aes_mul(0x0b,a3);s[c+3]=aes_mul(0x0b,a0)^aes_mul(0x0d,a1)^aes_mul(0x09,a2)^aes_mul(0x0e,a3);}}
static void aes128_enc_block(const uint8_t in[16],uint8_t out[16],const uint8_t rk[176]){uint8_t s[16];memcpy(s,in,16);aes_ark(s,rk);for(int r=1;r<=9;r++){aes_sb(s);aes_sr(s);aes_mc(s);aes_ark(s,rk+16*r);}aes_sb(s);aes_sr(s);aes_ark(s,rk+160);memcpy(out,s,16);}
static void aes128_dec_block(const uint8_t in[16],uint8_t out[16],const uint8_t rk[176]){uint8_t s[16];memcpy(s,in,16);aes_ark(s,rk+160);for(int r=9;r>=1;r--){aes_isr(s);aes_isb(s);aes_ark(s,rk+16*r);aes_imc(s);}aes_isr(s);aes_isb(s);aes_ark(s,rk);memcpy(out,s,16);}
static void aes128_cbc_enc(const uint8_t*in,uint8_t*out,size_t len,const uint8_t key[16],const uint8_t iv[16]){uint8_t rk[176];aes128_key_expand(key,rk);uint8_t p[16];memcpy(p,iv,16);for(size_t i=0;i<len;i+=16){uint8_t b[16];for(int j=0;j<16;j++)b[j]=in[i+j]^p[j];aes128_enc_block(b,out+i,rk);memcpy(p,out+i,16);}}
static void aes128_cbc_dec(const uint8_t*in,uint8_t*out,size_t len,const uint8_t key[16],const uint8_t iv[16]){uint8_t rk[176];aes128_key_expand(key,rk);uint8_t p[16];memcpy(p,iv,16);for(size_t i=0;i<len;i+=16){uint8_t b[16];aes128_dec_block(in+i,b,rk);for(int j=0;j<16;j++)out[i+j]=b[j]^p[j];memcpy(p,in+i,16);}}
